import{_ as t,o as a,c as r,a3 as s}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"95. Supplementary Roster","description":"","frontmatter":{"title":"95. Supplementary Roster","eba":"Mental Health Services 2024-2028","topics":["hours","rosters"]},"headers":[],"relativePath":"ebas/mental-health/rpn-pen-mho/hours-of-work/95-supplementary-roster.md","filePath":"ebas/mental-health/rpn-pen-mho/hours-of-work/95-supplementary-roster.md"}'),o={name:"ebas/mental-health/rpn-pen-mho/hours-of-work/95-supplementary-roster.md"};function n(i,e,l,h,p,c){return a(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="_95-supplementary-roster" tabindex="-1">95. Supplementary Roster <a class="header-anchor" href="#_95-supplementary-roster" aria-label="Permalink to &quot;95. Supplementary Roster&quot;">​</a></h1><p><strong>95.1</strong> In addition to the roster under <a href="/eba/ebas/mental-health/rpn-pen-mho/hours-of-work/94-rosters.html">clause 94</a> (Rosters), the Employer will maintain a supplementary roster.</p><p><strong>95.2</strong> A supplementary roster facilitates additional shifts worked on a voluntary basis. The supplementary roster will:</p><p><strong>(a)</strong> display vacant shifts, at a point in time, which Employee can nominate to work; and</p><p><strong>(b)</strong> contain a &#39;stand-by&#39; facility where Employees wishing to work extra shifts can nominate the days / shifts they wish to work should such vacancies arise in the normal roster.</p><p><strong>95.3</strong> Vacancies that arise in the normal roster issued under <a href="/eba/ebas/mental-health/rpn-pen-mho/leave/98-public-holidays.html">clause 98</a> will, as far as possible, be filled through the supplementary roster.</p><p><strong>95.4</strong> If a vacancy in the roster:</p><p><strong>(a)</strong> is filled under the supplementary roster, the additional shift is an &#39;additional shift worked by agreement&#39; and does not attract the &#39;change of roster&#39; allowance under <a href="/eba/ebas/mental-health/rpn-pen-mho/hours-of-work/94-rosters.html">clause 94</a> (Rosters);</p><p><strong>(b)</strong> cannot be filled from the supplementary roster, an Employee may be requested to work an additional shift (subject to the provisions of this Agreement and the additional shift attracts the “change of roster allowance” in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a>, in addition to any other entitlement on each such occasion.</p><p><strong>95.5</strong> Nothing in this clause prevents an Employer from operating an electronic supplementary roster, provided it meets the objectives of subclause 95.2 above.</p><p><strong>95.6</strong> Where an Employee is requested by the Employer to work an additional shift other than by the supplementary roster, each such additional shift worked will attract the &#39;change of roster allowance&#39; in <a href="/eba/ebas/mental-health/schedules/02-salaries-and-allowances.html">Schedule 2</a> in addition to any other entitlement on each such occasion.</p><p><strong>95.7</strong> A contract of employment that requires an Employee be available for extra shifts does not override this provision.</p><p><strong>95.8</strong> Overtime remains payable where it would otherwise apply, such as double shifts (for hours in addition to ordinary hours) and recall.</p><p><strong>95.9</strong> This clause does not inhibit Employees swapping shifts amongst themselves (subject to operational requirements) in which case no change of roster allowance is payable.</p>',14)])])}const u=t(o,[["render",n]]);export{d as __pageData,u as default};
